// Unity Editor dark theme icons (base64 embedded)
const ICONS: Record<string, string> = {
  unity: "data:image/png;base64,",
  prefab: "data:image/png;base64,",
  fbx: "data:image/png;base64,",
  mat: "data:image/png;base64,",
  cs: "data:image/png;base64,",
  png: "data:image/png;base64,",
  anim: "data:image/png;base64,",
  folder: "data:image/png;base64,",
  controller: "data:image/png;base64,",
  wav: "data:image/png;base64,",
  lighting: "data:image/png;base64,",
  txt: "data:image/png;base64,",
};

const EXT_MAP: Record<string, string> = {
  unity:"unity",prefab:"prefab",
  fbx:"fbx",blend:"fbx",obj:"fbx",mesh:"fbx",
  mat:"mat",material:"mat",shader:"mat",shadergraph:"mat",
  cs:"cs",
  png:"png",jpg:"png",tga:"png",psd:"png",exr:"png",tiff:"png",
  anim:"anim",
  controller:"controller",overridecontroller:"controller",
  lighting:"lighting",
  wav:"wav",mp3:"wav",ogg:"wav",
  txt:"txt",json:"txt",xml:"txt",asset:"txt",
  folder:"folder",
};

export function getIconSrc(ext: string): string {
  const key = EXT_MAP[ext?.toLowerCase()] || "txt";
  return ICONS[key] || ICONS.txt;
}

export function getExt(filename: string): string {
  return filename.includes(".") ? filename.split(".").pop()!.toLowerCase() : "folder";
}
